Prolog:
sTextKey = Trim(pTextKey);
sRequestedLocale = Trim(pLocale);
sOutputFile = Trim(pOutputFile);
sResolvedText = '';
sResolvedLocale = '';
sStatus = 'MISSING';
sComment = '';
sMissingMarker = '[missing:' | sTextKey | ']';
If(sRequestedLocale @= ''); sRequestedLocale = 'en-US'; EndIf;
If(sTextKey @= '');
  sStatus = 'ERROR';
  sComment = 'Text key is required.';
  sResolvedText = '[missing:]';
  sResolvedLocale = sRequestedLocale;
ElseIf(CubeExists('IMF.C.Text') = 0);
  sStatus = 'ERROR';
  sComment = 'IMF.C.Text is not deployed.';
  sResolvedText = sMissingMarker;
  sResolvedLocale = sRequestedLocale;
ElseIf(DimensionElementExists('IMF.D.TextKey', sTextKey) = 0);
  sStatus = 'ERROR';
  sComment = 'Text key is not deployed in IMF.D.TextKey.';
  sResolvedText = sMissingMarker;
  sResolvedLocale = sRequestedLocale;
Else;
  sResolvedText = CellGetS('IMF.C.Text', sTextKey, sRequestedLocale, 'Text');
  If(Trim(sResolvedText) @<> '');
    sStatus = 'FOUND';
    sResolvedLocale = sRequestedLocale;
    sComment = 'Translation found for requested locale.';
  Else;
    sResolvedText = CellGetS('IMF.C.Text', sTextKey, 'en-US', 'Text');
    If(Trim(sResolvedText) @<> '');
      sStatus = 'FALLBACK';
      sResolvedLocale = 'en-US';
      sComment = 'Requested locale missing. Fallback to en-US applied.';
    Else;
      sStatus = 'MISSING';
      sResolvedLocale = 'en-US';
      sResolvedText = sMissingMarker;
      sComment = 'Requested locale and en-US baseline are both missing.';
    EndIf;
  EndIf;
EndIf;
If(sOutputFile @<> '');
  ASCIIOutput(sOutputFile, 'TextKey', 'RequestedLocale', 'ResolvedLocale', 'Status', 'ResolvedText', 'Comment');
  ASCIIOutput(sOutputFile, sTextKey, sRequestedLocale, sResolvedLocale, sStatus, sResolvedText, sComment);
Else;
  LogOutput('INFO', 'IMF.P.Text.ResolveWithFallback|' | sTextKey | '|' | sRequestedLocale | '|' | sResolvedLocale | '|' | sStatus | '|' | sResolvedText);
EndIf;

